public class Person
{
    public string FirstName { get; set; }
    public string LastName { get; set; }

    public Person(string firstName, string lastName)
    {
        FirstName = firstName;
        LastName = lastName;
    }
}

public static class Helpers
{
    public static string ToUpperName(Person person)
    {
        return $"{person.FirstName.ToUpper()} {person.LastName.ToUpper()}";
    }
}

